$ignorez 1 // This is a logical setting. It is mainly used for interface materials that will always be in front of the 3D world, and skybox materials that will always be behind it. 
 "$basetexture" "skybox/ts_constrybk" // Texture directory (Where the sky texture is located strictly in the "skybox/" directory). 
